# Entities module with classes, inherits from types_module
from types_module import IDrawable, IMeasurable, Color, Point
from utils_module import format_color, scale_point

@abstract
class Shape(IDrawable, IMeasurable):
    color: Color
    position: Point

    def __init__(self, color: Color, position: Point):
        self.color = color
        self.position = position

    @virtual
    def describe(self) -> str:
        return f"Shape at ({self.position.x}, {self.position.y})"

    def draw(self) -> str:
        return f"Drawing {self.color.name} shape"

class Circle(Shape):
    radius: float

    def __init__(self, color: Color, position: Point, radius: float):
        super().__init__(color, position)
        self.radius = radius

    @override
    def describe(self) -> str:
        return f"Circle with radius {self.radius}"

    def get_area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def get_perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, color: Color, position: Point, width: float, height: float):
        super().__init__(color, position)
        self.width = width
        self.height = height

    @override
    def describe(self) -> str:
        return f"Rectangle {self.width} x {self.height}"

    def get_area(self) -> float:
        return self.width * self.height

    def get_perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    def get_scaled_position(self) -> Point:
        return scale_point(self.position, 2.0)
